<!DOCTYPE html>
<html lang="id">
<head>
    <meta charset="UTF-8"/>
    <meta name="viewport" content="width=device-width,initial-scale=1.0"/>
    <title>Dashboard Monitoring Bencana Sumatera & Aceh</title>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link href="https://fonts.googleapis.com/css2?family=DM+Serif+Display:ital@0;1&family=DM+Sans:ital,opsz,wght@0,9..40,300;0,9..40,400;0,9..40,500;0,9..40,600;0,9..40,700;1,9..40,300&display=swap" rel="stylesheet">
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.css"/>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.js"></script>
    <style>
        *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
        :root{
            --ink:#1c1a16;--ink2:#3a3730;--ink3:#6a6558;
            --paper:#f5f1eb;--paper2:#ede8e0;--paper3:#e4ddd2;
            --white:#fdfaf6;--border:#d8d0c4;--border2:#c8bfb0;
            --accent:#2c5545;--accent2:#3d7060;--accent-light:#e0ede8;
            --red:#8b2a22;--red-light:#f5e8e6;
            --orange:#8b5e1a;--orange-light:#f5ede0;
            --green:#1a5c30;--green-light:#e0f0e6;
            --yellow:#7a6a1a;--yellow-light:#f5f0d8;
            --blue:#1a3a6a;--blue-light:#e0e8f5;
            --panel-bg:rgba(253,250,246,0.97);
            --shadow:0 4px 24px rgba(28,26,22,0.12);
            --shadow-lg:0 8px 48px rgba(28,26,22,0.18);
        }
        html,body{width:100%;min-height:100%;font-family:'DM Sans',sans-serif;background:var(--paper);color:var(--ink);font-size:13px;}

        /* ── TOP BAR ── */
        #topbar{
            position:sticky;top:0;z-index:200;
            height:56px;background:var(--panel-bg);
            border-bottom:1px solid var(--border);
            backdrop-filter:blur(12px);
            display:flex;align-items:center;
            padding:0 28px;gap:18px;
            box-shadow:0 2px 12px rgba(28,26,22,0.07);
        }
        .brand-title{font-family:'DM Serif Display',serif;font-size:15px;color:var(--ink);line-height:1.2;}
        .brand-sub{font-size:12px;color:var(--ink3);letter-spacing:.08em;text-transform:uppercase;margin-top:1px;}
        .divider-v{width:1px;height:28px;background:var(--border);flex-shrink:0;}
        .status-chip{padding:5px 13px;border-radius:999px;font-size:11px;font-weight:600;letter-spacing:.04em;display:flex;align-items:center;gap:6px;flex-shrink:0;background:var(--orange-light);color:var(--orange);border:1px solid #e0c090;}
        .dot{width:7px;height:7px;border-radius:50%;background:currentColor;animation:pulse 1.5s infinite;}
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:.4}}
        .ksp-badge{font-size:12px;color:var(--ink3);text-align:right;line-height:1.5;flex-shrink:0;margin-left:auto;}

        /* ── HEADER SECTION ── */
        #page-header{
            background:var(--white);border-bottom:1px solid var(--border);
            padding:28px 40px 22px;
            display:flex;align-items:flex-start;justify-content:space-between;gap:24px;
        }
        .ph-left{}
        .ph-eyebrow{font-size:10.5px;letter-spacing:.12em;text-transform:uppercase;color:var(--ink3);font-weight:600;margin-bottom:6px;}
        .ph-title{font-family:'DM Serif Display',serif;font-size:32px;line-height:1.1;color:var(--ink);}
        .ph-logos{display:flex;align-items:center;gap:12px;flex-shrink:0;}
        .ph-logo{width:56px;height:56px;background:var(--paper2);border:1px solid var(--border);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:26px;}
        .ph-logo-label{font-size:12px;color:var(--ink3);text-align:center;line-height:1.4;margin-top:4px;font-weight:500;}
        .ph-logo-wrap{display:flex;flex-direction:column;align-items:center;}

        /* ── STATUS BANNER ── */
        #status-banner{
            margin:20px 40px;padding:14px 18px;
            background:var(--accent-light);border:1.5px solid var(--accent2);border-radius:10px;
            display:flex;align-items:flex-start;gap:12px;
        }
        .sb-icon{font-size:18px;margin-top:1px;flex-shrink:0;}
        .sb-title{font-size:11px;font-weight:700;letter-spacing:.08em;text-transform:uppercase;color:var(--accent);margin-bottom:4px;}
        .sb-text{font-size:13px;color:var(--ink2);line-height:1.6;}

        /* ── CATEGORY TABS ── */
        #cat-tabs{
            display:flex;align-items:center;gap:0;
            padding:0 40px;
            border-bottom:2px solid var(--border);
            background:var(--white);
        }
        .tab-btn{
            padding:12px 20px;font-size:12px;font-weight:600;
            border:none;background:transparent;cursor:pointer;
            color:var(--ink3);font-family:'DM Sans',sans-serif;
            border-bottom:3px solid transparent;margin-bottom:-2px;
            display:flex;align-items:center;gap:6px;
            transition:all .15s;letter-spacing:.02em;
            white-space:nowrap;
        }
        .tab-btn:hover{color:var(--ink);}
        .tab-btn.active{color:var(--accent);border-bottom-color:var(--accent);}
        .tab-btn .tab-icon{font-size:14px;}
        .tab-label-row{display:flex;align-items:center;gap:8px;padding:10px 40px 0;margin-bottom:8px;}
        .tab-showing{font-size:11.5px;color:var(--ink3);}
        .tab-showing strong{color:var(--ink);font-weight:700;}
        .tab-back{font-size:11.5px;color:var(--accent2);cursor:pointer;display:flex;align-items:center;gap:4px;font-weight:600;}
        .tab-back:hover{text-decoration:underline;}

        /* ── MAIN CONTENT GRID ── */
        #main-content{
            display:grid;grid-template-columns:1fr 340px;
            gap:0;padding:0 40px 32px;margin-top:12px;
        }
        .left-col{display:flex;flex-direction:column;gap:16px;padding-right:20px;}
        .right-col{display:flex;flex-direction:column;gap:16px;}

        /* ── MAP CARD ── */
        #map-card{
            background:var(--white);border:1px solid var(--border);border-radius:12px;
            overflow:hidden;box-shadow:var(--shadow);
            position:relative;
        }
        #map-card .map-inner{
            position:relative;height:440px;width:100%;
        }
        #the-map{width:100%;height:100%;}
        .map-source{
            position:absolute;bottom:0;left:0;right:0;
            background:rgba(253,250,246,.88);border-top:1px solid var(--border);
            padding:6px 12px;font-size:12px;color:var(--ink3);
            backdrop-filter:blur(4px);
        }

        /* Province popup on map */
        #prov-popup{
            position:absolute;left:12px;bottom:40px;z-index:400;
            background:var(--panel-bg);border:1px solid var(--border);border-radius:10px;
            padding:14px 16px;min-width:230px;
            box-shadow:var(--shadow);backdrop-filter:blur(12px);
            opacity:0;transform:translateY(6px);
            transition:opacity .25s,transform .25s;pointer-events:none;
        }
        #prov-popup.visible{opacity:1;transform:translateY(0);pointer-events:auto;}
        .pp-name{font-family:'DM Serif Display',serif;font-size:16px;color:var(--ink);margin-bottom:8px;display:flex;align-items:center;gap:6px;}
        .pp-dot{width:10px;height:10px;border-radius:50%;flex-shrink:0;}
        .pp-row{display:flex;justify-content:space-between;font-size:11.5px;margin-bottom:4px;}
        .pp-label{color:var(--ink3);}
        .pp-val{font-weight:600;color:var(--ink);}
        .pp-bar-wrap{height:5px;background:var(--paper3);border-radius:3px;margin-bottom:8px;overflow:hidden;}
        .pp-bar-fill{height:100%;border-radius:3px;}
        .pp-chevron{font-size:11px;color:var(--ink3);margin-left:4px;}

        /* ── CRITICAL ISSUES CARD ── */
        .card{
            background:var(--white);border:1px solid var(--border);border-radius:12px;
            padding:16px 18px;box-shadow:var(--shadow);
        }
        .card-title{font-size:12px;font-weight:700;color:var(--ink);letter-spacing:.04em;text-transform:uppercase;margin-bottom:12px;}
        .critical-list{display:flex;flex-direction:column;gap:10px;}
        .crit-item{display:flex;align-items:center;gap:10px;padding:10px 12px;border-radius:8px;border:1px solid var(--border);}
        .crit-item.red-item{background:var(--red-light);border-color:#e0b0ac;}
        .crit-item.orange-item{background:var(--orange-light);border-color:#e0c090;}
        .crit-icon{font-size:20px;flex-shrink:0;}
        .crit-text{font-size:12px;font-weight:600;color:var(--ink);line-height:1.3;}

        /* ── PHOTO CARD ── */
        .photo-pair{display:grid;grid-template-columns:1fr auto 1fr;gap:6px;align-items:center;}
        .photo-box{aspect-ratio:4/3;background:var(--paper2);border-radius:8px;overflow:hidden;position:relative;border:1px solid var(--border);}
        .photo-box img{width:100%;height:100%;object-fit:cover;}
        .photo-box-placeholder{width:100%;height:100%;display:flex;align-items:center;justify-content:center;font-size:32px;color:var(--ink3);}
        .photo-lbl{position:absolute;bottom:0;left:0;right:0;background:rgba(28,26,22,.55);color:#fff;font-size:11px;font-weight:700;text-align:center;padding:4px;letter-spacing:.08em;}
        .photo-arrow{font-size:22px;color:var(--ink3);display:flex;align-items:center;}

        /* ── PROGRESS SECTION ── */
        #progress-section{
            background:var(--white);border:1px solid var(--border);border-radius:12px;
            box-shadow:var(--shadow);overflow:hidden;
        }
        .progress-header{
            padding:14px 20px;border-bottom:1px solid var(--border);
            display:flex;align-items:center;justify-content:space-between;cursor:pointer;
        }
        .progress-header-title{font-size:11.5px;font-weight:700;letter-spacing:.06em;text-transform:uppercase;color:var(--ink);}
        .progress-header-arrow{font-size:12px;color:var(--ink3);transition:transform .2s;}
        .progress-body{padding:18px 20px 20px;display:grid;grid-template-columns:1fr 1fr 1fr;gap:20px;}
        .prog-item{}
        .prog-top{display:flex;align-items:center;justify-content:space-between;margin-bottom:6px;}
        .prog-name{font-size:12px;font-weight:600;color:var(--ink2);display:flex;align-items:center;gap:6px;}
        .prog-icon{font-size:14px;}
        .prog-pct{font-size:14px;font-weight:700;color:var(--ink);}
        .prog-bar-bg{height:6px;background:var(--paper3);border-radius:3px;overflow:hidden;}
        .prog-bar-fill{height:100%;border-radius:3px;transition:width .8s ease;}
        .prog-source{padding:0 20px 12px;font-size:12px;color:var(--ink3);}

        /* ── BOTTOM NAV ── */
        #bottom-nav{
            position:sticky;bottom:0;z-index:200;
            background:var(--ink);display:flex;align-items:center;gap:0;
            padding:0 0;
        }
        .bnav-btn{
            padding:14px 24px;font-size:12px;font-weight:600;
            border:none;background:transparent;cursor:pointer;
            color:rgba(255,255,255,.55);font-family:'DM Sans',sans-serif;
            letter-spacing:.02em;transition:color .15s;white-space:nowrap;
            border-right:1px solid rgba(255,255,255,.1);
        }
        .bnav-btn:hover{color:#fff;}
        .bnav-btn.active{color:#fff;background:rgba(255,255,255,.1);}
        .bnav-more{margin-left:auto;padding:14px 20px;font-size:16px;color:rgba(255,255,255,.4);cursor:pointer;border-left:1px solid rgba(255,255,255,.1);}

        /* ── OVERVIEW KPIs ROW ── */
        .kpi-row{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:4px;}
        .kpi-card{background:var(--white);border:1px solid var(--border);border-radius:8px;padding:10px 12px;}
        .kpi-val{font-family:'DM Serif Display',serif;font-size:22px;color:var(--ink);}
        .kpi-label{font-size:12px;color:var(--ink3);margin-top:2px;line-height:1.3;}
        .kpi-tag{display:inline-block;padding:2px 8px;border-radius:999px;font-size:11px;font-weight:700;margin-top:5px;}
        .kpi-tag.green{background:var(--green-light);color:var(--green);}
        .kpi-tag.red{background:var(--red-light);color:var(--red);}
        .kpi-tag.orange{background:var(--orange-light);color:var(--orange);}

        /* Legend */
        .map-legend{display:flex;gap:12px;flex-wrap:wrap;padding:10px 14px;border-top:1px solid var(--border);background:var(--paper);}
        .leg-item{display:flex;align-items:center;gap:5px;font-size:11px;color:var(--ink2);}
        .leg-dot{width:10px;height:10px;border-radius:2px;flex-shrink:0;}

        /* Leaflet overrides */
        .leaflet-control-attribution{display:none!important;}
        .leaflet-control-zoom{border:none!important;box-shadow:var(--shadow)!important;}
        .leaflet-control-zoom a{background:var(--panel-bg)!important;color:var(--ink)!important;border:1px solid var(--border)!important;}
        .leaflet-control-zoom a:hover{background:var(--paper2)!important;}
    </style>
</head>
<body>

<!-- TOP BAR -->
<div id="topbar">
    <div>
        <div class="brand-title">Monitoring Bencana</div>
        <div class="brand-sub">Sumatera &amp; Aceh — KSP</div>
    </div>
    <div class="divider-v"></div>
    <div class="status-chip"><span class="dot"></span>Penanganan Masih Berlangsung</div>
    <div class="ksp-badge">Update: 10 Feb 2026<br>Kementerian Dalam Negeri</div>
</div>

<!-- PAGE HEADER -->
<div id="page-header">
    <div class="ph-left">
        <div class="ph-eyebrow">Dashboard</div>
        <div class="ph-title">Monitoring Penanganan<br>Bencana Sumatera &amp; Aceh</div>
    </div>
</div>

<!-- STATUS BANNER -->
<div id="status-banner">
    <div class="sb-icon">✅</div>
    <div>
        <div class="sb-title">Status: Penanganan Masih Berlangsung</div>
        <div class="sb-text">Per 10 Februari 2026, 65% infrastruktur terdampak telah pulih. Masalah utama terdapat pada jalan dan listrik di wilayah Sumatera Barat.</div>
    </div>
</div>

<!-- CATEGORY TABS -->
<div id="cat-tabs">
    <button class="tab-btn" onclick="setTab(this,'semua')"><span class="tab-icon">📋</span>Semua</button>
    <button class="tab-btn active" onclick="setTab(this,'infrastruktur')"><span class="tab-icon">🏗️</span>Infrastruktur</button>
    <button class="tab-btn" onclick="setTab(this,'faskes')"><span class="tab-icon">🏥</span>Faskes</button>
    <button class="tab-btn" onclick="setTab(this,'pendidikan')"><span class="tab-icon">🎓</span>Pendidikan</button>
    <button class="tab-btn" onclick="setTab(this,'sosial')"><span class="tab-icon">🏘️</span>Sosial</button>
</div>
<div class="tab-label-row">
    <span class="tab-showing">Menampilkan: <strong id="active-tab-label">INFRASTRUKTUR</strong></span>
    <span style="flex:1"></span>
    <span class="tab-back" onclick="setTabByName('semua')">Kembali ke SEMUA ›</span>
</div>

<!-- MAIN CONTENT -->
<div id="main-content">

    <!-- LEFT COLUMN -->
    <div class="left-col">

        <!-- KPIs -->
        <div class="kpi-row">
            <div class="kpi-card">
                <div class="kpi-val">65%</div>
                <div class="kpi-label">Infrastruktur Pulih</div>
                <div class="kpi-tag green">↑ On Track</div>
            </div>
            <div class="kpi-card">
                <div class="kpi-val">120 km</div>
                <div class="kpi-label">Jalan Belum Diperbaiki</div>
                <div class="kpi-tag red">⚠ Kritis</div>
            </div>
            <div class="kpi-card">
                <div class="kpi-val">15</div>
                <div class="kpi-label">Desa Masih Padam</div>
                <div class="kpi-tag orange">Aktif</div>
            </div>
        </div>

        <!-- MAP CARD -->
        <div id="map-card">
            <div class="map-inner">
                <div id="the-map"></div>
                <div id="prov-popup">
                    <div class="pp-name"><span class="pp-dot" id="pp-dot" style="background:#8b4a4a"></span><span id="pp-name-text">Sumatera Barat</span><span class="pp-chevron">›</span></div>
                    <div class="pp-row"><span class="pp-label">Persentase Pulih</span><span class="pp-val" id="pp-pct">49%</span></div>
                    <div class="pp-bar-wrap"><div class="pp-bar-fill" id="pp-bar" style="width:49%;background:#e8a838"></div></div>
                    <div class="pp-row"><span class="pp-label">Jalan Rusak Belum Diperbaiki</span><span class="pp-val">84 km</span></div>
                    <div class="pp-row"><span class="pp-label">Desa Masih Padam</span><span class="pp-val">12 desa</span></div>
                </div>
            </div>
            <div class="map-legend">
                <div class="leg-item"><div class="leg-dot" style="background:#4a7c59"></div>Aceh</div>
                <div class="leg-item"><div class="leg-dot" style="background:#8b4a4a"></div>Sumatera Utara</div>
                <div class="leg-item"><div class="leg-dot" style="background:#7a6a3a"></div>Sumatera Barat</div>
                <span style="margin-left:auto;font-size:12px;color:var(--ink3);">Klik wilayah untuk detail</span>
            </div>
            <div class="map-source">Sumber: GIS BNPB | Update: 10 Februari 2026</div>
        </div>

        <!-- PROGRESS SECTION -->
        <div id="progress-section">
            <div class="progress-header" onclick="toggleProgress()">
                <div class="progress-header-title">📊 Progress Penanganan Infrastruktur</div>
                <div class="progress-header-arrow" id="prog-arrow">▲</div>
            </div>
            <div class="progress-body" id="prog-body">
                <div class="prog-item">
                    <div class="prog-top">
                        <div class="prog-name"><span class="prog-icon">⚠️</span>Jalan</div>
                        <div class="prog-pct">65%</div>
                    </div>
                    <div class="prog-bar-bg"><div class="prog-bar-fill" style="width:65%;background:linear-gradient(90deg,#e8a838,#c97b22)"></div></div>
                </div>
                <div class="prog-item">
                    <div class="prog-top">
                        <div class="prog-name"><span class="prog-icon">⚡</span>Listrik</div>
                        <div class="prog-pct">83%</div>
                    </div>
                    <div class="prog-bar-bg"><div class="prog-bar-fill" style="width:83%;background:linear-gradient(90deg,#52a86a,#2d6a3a)"></div></div>
                </div>
                <div class="prog-item">
                    <div class="prog-top">
                        <div class="prog-name"><span class="prog-icon">💧</span>Air Bersih</div>
                        <div class="prog-pct">72%</div>
                    </div>
                    <div class="prog-bar-bg"><div class="prog-bar-fill" style="width:72%;background:linear-gradient(90deg,#52a86a,#2d6a3a)"></div></div>
                </div>
            </div>
            <div class="prog-source">Sumber: GIS BNPB | Update: 10 Februari 2026</div>
        </div>

    </div><!-- /left-col -->

    <!-- RIGHT COLUMN -->
    <div class="right-col">

        <!-- Critical Issues -->
        <div class="card">
            <div class="card-title">⚠ Masalah Kritis</div>
            <div class="critical-list">
                <div class="crit-item red-item">
                    <span class="crit-icon">🛤️</span>
                    <div class="crit-text">120 Km Jalan<br>Belum Diperbaiki</div>
                </div>
                <div class="crit-item orange-item">
                    <span class="crit-icon">⚡</span>
                    <div class="crit-text">15 Desa Masih<br>Padam</div>
                </div>
                <div class="crit-item red-item">
                    <span class="crit-icon">🌉</span>
                    <div class="crit-text">3 Jembatan<br>Rusak Berat</div>
                </div>
            </div>
        </div>

        <!-- Sumatera Barat Detail -->
        <div class="card">
            <div class="card-title" style="display:flex;align-items:center;justify-content:space-between;">
                <span>📍 Sumatera Barat</span>
                <span style="font-size:11px;color:var(--accent2);cursor:pointer;font-weight:600;">Lihat Detail ›</span>
            </div>
            <div class="pp-row"><span class="pp-label">Persentase Pulih</span><span class="pp-val" style="font-size:15px;">49%</span></div>
            <div class="pp-bar-wrap" style="margin:6px 0 10px;height:7px;"><div class="pp-bar-fill" style="width:49%;background:linear-gradient(90deg,#e8a838,#c97b22);"></div></div>
            <div style="display:flex;flex-direction:column;gap:6px;margin-bottom:12px;">
                <div style="display:flex;align-items:center;gap:8px;font-size:12px;color:var(--ink2);">
                    <span style="font-size:14px;">🛤️</span><span>84 Km Jalan Rusak Belum Diperbaiki</span>
                </div>
                <div style="display:flex;align-items:center;gap:8px;font-size:12px;color:var(--ink2);">
                    <span style="font-size:14px;">⚡</span><span>12 Desa Masih Padam</span>
                </div>
            </div>
            <!-- Photo pair -->
            <div class="photo-pair">
                <div class="photo-box">
                    <div class="photo-box-placeholder">🏚️</div>
                    <div class="photo-lbl">SEBELUM</div>
                </div>
                <div class="photo-arrow">›</div>
                <div class="photo-box">
                    <div class="photo-box-placeholder">🏗️</div>
                    <div class="photo-lbl">SESUDAH</div>
                </div>
            </div>
        </div>

        <!-- Foto Lapangan -->
        <div class="card">
            <div class="card-title">📸 Foto Lapangan</div>
            <div class="photo-pair">
                <div class="photo-box" style="aspect-ratio:3/2;">
                    <div class="photo-box-placeholder">🛤️</div>
                    <div class="photo-lbl">SEBELUM</div>
                </div>
                <div class="photo-arrow">›</div>
                <div class="photo-box" style="aspect-ratio:3/2;">
                    <div class="photo-box-placeholder">🚧</div>
                    <div class="photo-lbl">SESUDAH</div>
                </div>
            </div>
            <div style="margin-top:10px;font-size:11px;color:var(--ink3);">Jalan Pesisir Selatan — Painan–Tapan</div>
        </div>

        <!-- Province Summary -->
