    // ── MAP ──
    const map = L.map('the-map', {
        center:[2.0, 98.5], zoom:6,
        zoomControl:true,
        attributionControl:false
    });
    L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png',{maxZoom:19}).addTo(map);

    // Draw province rectangles
    const geoLayers = {};
    Object.entries(SIMPLE_GEO).forEach(([slug, prov]) => {
        const layer = L.geoJSON({ type:'Feature', geometry: prov.geometry }, {
            style: {
                color: prov.color, weight: 2, opacity: 0.85,
                fillColor: prov.color, fillOpacity: 0.18,
            }
        });
        layer.on('mouseover', (e) => {
            e.target.setStyle({ fillOpacity: 0.38, weight: 3 });
            showPop(slug);
        });
        layer.on('mouseout', (e) => {
            e.target.setStyle({ fillOpacity: 0.18, weight: 2 });
        });
        layer.addTo(map);
        geoLayers[slug] = layer;
    });

    // Add km markers (like the image)
    const kmMarkers = [
        {lat:3.5, lng:96.8, label:'5 Km'},
        {lat:2.9, lng:97.5, label:'8 Km'},
        {lat:2.3, lng:97.7, label:'14 Km'},
        {lat:2.0, lng:98.3, label:'5 Km'},
        {lat:1.2, lng:99.4, label:'14 Km'},
    ];
    kmMarkers.forEach(m => {
        L.marker([m.lat,m.lng], {
            icon: L.divIcon({
                html:`<div style="background:#e8a838;color:#fff;font-size:11px;font-weight:700;padding:3px 7px;border-radius:999px;white-space:nowrap;box-shadow:0 2px 6px rgba(0,0,0,.2)">${m.label}</div>`,
                className:'',iconAnchor:[20,10]
            })
        }).addTo(map);
    });

    // Warning icons
    const warnings = [
        {lat:2.8, lng:97.4},
        {lat:1.9, lng:98.0},
        {lat:1.1, lng:99.6},
    ];
    warnings.forEach(w => {
        L.marker([w.lat,w.lng], {
            icon: L.divIcon({
                html:`<div style="font-size:18px;filter:drop-shadow(0 1px 2px rgba(0,0,0,.3))">⚠️</div>`,
                className:'',iconAnchor:[9,9]
            })
        }).addTo(map);
    });

    function showPop(slug) {
        const p = PROVINCES[slug];
        const g = SIMPLE_GEO[slug];
        document.getElementById('pp-dot').style.background = g.color;
        document.getElementById('pp-name-text').textContent = p.name;
        document.getElementById('pp-pct').textContent = p.pct + '%';
        const bar = document.getElementById('pp-bar');
        bar.style.width = p.pct + '%';
        bar.style.background = p.pct>=70?'#52a86a':p.pct>=50?'#e8a838':'#e8534a';
        document.getElementById('prov-popup').classList.add('visible');
    }
    map.on('click', () => {
        setTimeout(() => document.getElementById('prov-popup').classList.remove('visible'), 150);
    });

    // ── TABS ──
    const tabLabels = {
        semua:'SEMUA', infrastruktur:'INFRASTRUKTUR',
        faskes:'FASKES', pendidikan:'PENDIDIKAN', sosial:'SOSIAL'
    };
    function setTab(el, id) {
        document.querySelectorAll('.tab-btn').forEach(b=>b.classList.remove('active'));
        el.classList.add('active');
        document.getElementById('active-tab-label').textContent = tabLabels[id]||id.toUpperCase();
    }
    function setTabByName(id) {
        const btns = document.querySelectorAll('.tab-btn');
        btns.forEach(b=>{if(b.textContent.toLowerCase().includes(id)){setTab(b,id);}});
    }

    // ── PROGRESS TOGGLE ──
    let progOpen = true;
    function toggleProgress() {
        progOpen = !progOpen;
        document.getElementById('prog-body').style.display = progOpen ? 'grid' : 'none';
        document.getElementById('prog-arrow').textContent = progOpen ? '▲' : '▾';
    }

    // ── BOTTOM NAV ──
    function setBNav(el){
        document.querySelectorAll('.bnav-btn').forEach(b=>{b.classList.remove('active');b.style.background='';b.style.color='rgba(255,255,255,.55)';});
        el.classList.add('active');el.style.background='rgba(255,255,255,0.1)';el.style.color='#fff';
    }
</script>
</body>
</html>
